sql:
SELECT username
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM model_runs
);

SELECT model_name, SUM(divergent) AS total_divergent_transitions
FROM model_runs
GROUP BY model_name;

SELECT run_id
FROM model_runs
WHERE end_time = (SELECT MAX(end_time) FROM model_runs);

SELECT user_id, timestamp
FROM model_audits
WHERE user_id = 2;

SELECT username
FROM users
WHERE user_id = (SELECT user_id FROM user_roles WHERE user_role_id = 0);

SELECT model_name
FROM model_statistics
WHERE divergent_count = 0;

SELECT model_name
FROM model_runs
WHERE energy = (SELECT MAX(energy) FROM model_runs);
